namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new()
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple yet delicious pizza with fresh mozzarella, tomatoes, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps =
                [
                    "Preheat oven to 475°F (245°C) with a pizza stone.",
                    "Stretch the dough into a 12-inch round.",
                    "Spread crushed tomatoes over the dough, leaving a 1-inch border.",
                    "Tear mozzarella into pieces and distribute evenly.",
                    "Bake for 10-12 minutes until crust is golden.",
                    "Top with fresh basil and a drizzle of olive oil."
                ],
                TotalRatings = 24, RatingSum = 108
            },
            new()
            {
                Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a creamy, spiced tomato sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato puree", "Heavy cream", "Onion", "Garlic", "Ginger", "Cilantro"],
                Steps =
                [
                    "Marinate chicken in yogurt and spices for at least 1 hour.",
                    "Grill or broil the chicken until charred.",
                    "Sauté onions, garlic, and ginger in a pan.",
                    "Add tomato puree and spices, simmer for 15 minutes.",
                    "Stir in cream and add the cooked chicken.",
                    "Simmer for 10 minutes and garnish with cilantro."
                ],
                TotalRatings = 18, RatingSum = 85
            },
            new()
            {
                Id = 3, Title = "Beef Tacos", Category = "Mexican",
                Description = "Flavorful seasoned beef in warm tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheese", "Sour cream", "Lime"],
                Steps =
                [
                    "Brown ground beef in a skillet over medium-high heat.",
                    "Add taco seasoning and water, simmer until thickened.",
                    "Warm tortillas in a dry skillet or microwave.",
                    "Fill tortillas with seasoned beef.",
                    "Top with lettuce, tomato, cheese, and sour cream.",
                    "Squeeze fresh lime over the tacos."
                ],
                TotalRatings = 15, RatingSum = 68
            },
            new()
            {
                Id = 4, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "A Roman classic with eggs, cheese, pancetta, and black pepper.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
                Steps =
                [
                    "Cook spaghetti in salted boiling water until al dente.",
                    "Crisp pancetta in a skillet until golden.",
                    "Whisk eggs and grated Pecorino together.",
                    "Toss hot pasta with pancetta, then remove from heat.",
                    "Quickly stir in the egg mixture, tossing constantly.",
                    "Season generously with black pepper and serve immediately."
                ],
                TotalRatings = 20, RatingSum = 92
            },
            new()
            {
                Id = 5, Title = "Pad Thai", Category = "Asian",
                Description = "Stir-fried rice noodles with shrimp, peanuts, and tangy sauce.",
                Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Peanuts", "Lime", "Fish sauce", "Tamarind paste", "Sugar"],
                Steps =
                [
                    "Soak rice noodles in warm water for 30 minutes.",
                    "Mix tamarind paste, fish sauce, and sugar for the sauce.",
                    "Stir-fry shrimp until pink, then set aside.",
                    "Scramble eggs in the same pan.",
                    "Add drained noodles and sauce, toss until coated.",
                    "Add shrimp and bean sprouts, top with peanuts and lime."
                ],
                TotalRatings = 12, RatingSum = 55
            },
            new()
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh and zesty avocado dip with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps =
                [
                    "Halve and pit the avocados, scoop into a bowl.",
                    "Mash to desired consistency with a fork.",
                    "Stir in diced onion, tomato, and jalapeño.",
                    "Add chopped cilantro, lime juice, and salt.",
                    "Taste and adjust seasoning.",
                    "Serve immediately with tortilla chips."
                ],
                TotalRatings = 10, RatingSum = 46
            },
            new()
            {
                Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Rich chocolate cake with a molten center.",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
                Steps =
                [
                    "Preheat oven to 425°F (220°C) and butter ramekins.",
                    "Melt chocolate and butter together in a double boiler.",
                    "Whisk eggs, sugar, and vanilla until thick.",
                    "Fold the chocolate mixture into the eggs, then add flour.",
                    "Pour into ramekins and bake for 12-14 minutes.",
                    "Invert onto plates and serve immediately."
                ],
                TotalRatings = 30, RatingSum = 142
            },
            new()
            {
                Id = 8, Title = "Miso Ramen", Category = "Asian",
                Description = "Hearty Japanese noodle soup with rich miso broth.",
                Ingredients = ["Ramen noodles", "Miso paste", "Chicken broth", "Soy sauce", "Soft-boiled egg", "Chashu pork", "Green onions", "Nori"],
                Steps =
                [
                    "Simmer chicken broth with miso paste and soy sauce.",
                    "Cook ramen noodles according to package directions.",
                    "Prepare soft-boiled eggs (6.5 minutes in boiling water).",
                    "Slice chashu pork and green onions.",
                    "Place noodles in bowls and ladle hot broth over them.",
                    "Top with pork, halved egg, green onions, and nori."
                ],
                TotalRatings = 14, RatingSum = 63
            }
        ];
        _nextId = 9;
    }

    public List<RecipeCategory> GetCategories()
    {
        return
        [
            new() { Name = "Italian", Icon = "🍝", Description = "Pasta, pizza, and Mediterranean flavors" },
            new() { Name = "Mexican", Icon = "🌮", Description = "Bold spices and fresh ingredients" },
            new() { Name = "Asian", Icon = "🍜", Description = "Noodles, stir-fries, and umami-rich dishes" },
            new() { Name = "Indian", Icon = "🍛", Description = "Aromatic curries and vibrant spices" },
            new() { Name = "Desserts", Icon = "🍰", Description = "Sweet treats and baked goods" }
        ];
    }

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;
        recipe.TotalRatings++;
        recipe.RatingSum += stars;
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }
}

