arguments.file_text:
@page "/"

<PageTitle>RecipeHub - Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 Welcome to RecipeHub</h1>
    <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<h2 class="mb-3">Browse by Category</h2>
<div class="row">
    @foreach (var category in Categories)
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100 shadow-sm">
                <div class="card-body text-center">
                    <div style="font-size: 3rem;">@category.Icon</div>
                    <h4 class="card-title mt-2">@category.Name</h4>
                    <p class="card-text text-muted">@category.Description</p>
                    <a href="category/@category.Name" class="btn btn-outline-primary">View Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private List<RecipeHub.Models.RecipeCategory> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }
}

@page "/category/{CategoryName}"

<PageTitle>@CategoryName Recipes - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    <span>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</span>
                                }
                                <small class="text-muted ms-1">(@recipe.TotalRatings)</small>
                            </span>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private List<RecipeHub.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <div class="alert alert-danger">Recipe not found.</div>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="lead text-muted">@Recipe.Description</p>

    <div class="row">
        <div class="col-md-4 mb-4">
            <div class="card">
                <div class="card-header"><strong>🥘 Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8 mb-4">
            <div class="card">
                <div class="card-header"><strong>📝 Steps</strong></div>
                <div class="card-body">
                    <ol class="mb-0">
                        @foreach (var step in Recipe.Steps)
                        {
                            <li class="mb-2">@step</li>
                        }
                    </ol>
                </div>
            </div>
        </div>
    </div>

    <div class="card mt-2">
        <div class="card-body">
            <h5>Rate this Recipe</h5>
            <p class="text-muted mb-2">
                Average: @Recipe.AverageRating.ToString("F1") / 5
                (@Recipe.TotalRatings ratings)
            </p>
            <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeHub.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer

<div class="d-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="font-size: 1.8rem; cursor: pointer; color: @(star <= HoveredStar ? "#ffc107" : "#dee2e6");"
              @onmouseover="() => HoveredStar = star"
              @onmouseout="() => HoveredStar = 0"
              @onclick="() => SubmitRating(star)">
            ★
        </span>
    }

    @if (Submitted)
    {
        <span class="badge bg-success ms-2">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private int HoveredStar;
    private bool Submitted;

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        Submitted = true;
        HoveredStar = stars;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📤 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (SubmittedSuccessfully)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added.
        <a href="recipe/@SubmittedId">View it here</a>.
    </div>
}

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label class="form-label">Title</label>
        <InputText @bind-Value="Model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => Model.Title" />
    </div>

    <div class="mb-3">
        <label class="form-label">Category</label>
        <InputSelect @bind-Value="Model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Mexican">Mexican</option>
            <option value="Asian">Asian</option>
            <option value="Indian">Indian</option>
            <option value="Desserts">Desserts</option>
        </InputSelect>
        <ValidationMessage For="() => Model.Category" />
    </div>

    <div class="mb-3">
        <label class="form-label">Description</label>
        <InputTextArea @bind-Value="Model.Description" class="form-control" rows="2"
                       placeholder="A brief description of the dish" />
        <ValidationMessage For="() => Model.Description" />
    </div>

    <div class="mb-3">
        <label class="form-label">Ingredients (one per line)</label>
        <InputTextArea @bind-Value="Model.IngredientsText" class="form-control" rows="5"
                       placeholder="Flour&#10;Sugar&#10;Butter" />
        <ValidationMessage For="() => Model.IngredientsText" />
    </div>

    <div class="mb-3">
        <label class="form-label">Steps (one per line)</label>
        <InputTextArea @bind-Value="Model.StepsText" class="form-control" rows="5"
                       placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Bake for 30 minutes" />
        <ValidationMessage For="() => Model.StepsText" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel Model { get; set; } = new();
    private bool SubmittedSuccessfully;
    private int SubmittedId;

    private void HandleSubmit()
    {
        var recipe = new RecipeHub.Models.Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Description = Model.Description,
            Ingredients = Model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = Model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeService.AddRecipe(recipe);
        SubmittedId = recipe.Id;
        SubmittedSuccessfully = true;
        Model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100)]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Description is required")]
        [System.ComponentModel.DataAnnotations.StringLength(500)]
        public string Description { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string IngredientsText { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string StepsText { get; set; } = string.Empty;
    }
}

