toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📤 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (SubmittedSuccessfully)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added.
        <a href="recipe/@SubmittedId">View it here</a>.
    </div>
}

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label class="form-label">Title</label>
        <InputText @bind-Value="Model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => Model.Title" />
    </div>

    <div class="mb-3">
        <label class="form-label">Category</label>
        <InputSelect @bind-Value="Model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Mexican">Mexican</option>
            <option value="Asian">Asian</option>
            <option value="Indian">Indian</option>
            <option value="Desserts">Desserts</option>
        </InputSelect>
        <ValidationMessage For="() => Model.Category" />
    </div>

    <div class="mb-3">
        <label class="form-label">Description</label>
        <InputTextArea @bind-Value="Model.Description" class="form-control" rows="2"
                       placeholder="A brief description of the dish" />
        <ValidationMessage For="() => Model.Description" />
    </div>

    <div class="mb-3">
        <label class="form-label">Ingredients (one per line)</label>
        <InputTextArea @bind-Value="Model.IngredientsText" class="form-control" rows="5"
                       placeholder="Flour&#10;Sugar&#10;Butter" />
        <ValidationMessage For="() => Model.IngredientsText" />
    </div>

    <div class="mb-3">
        <label class="form-label">Steps (one per line)</label>
        <InputTextArea @bind-Value="Model.StepsText" class="form-control" rows="5"
                       placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Bake for 30 minutes" />
        <ValidationMessage For="() => Model.StepsText" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel Model { get; set; } = new();
    private bool SubmittedSuccessfully;
    private int SubmittedId;

    private void HandleSubmit()
    {
        var recipe = new RecipeHub.Models.Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Description = Model.Description,
            Ingredients = Model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = Model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeService.AddRecipe(recipe);
        SubmittedId = recipe.Id;
        SubmittedSuccessfully = true;
        Model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100)]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Description is required")]
        [System.ComponentModel.DataAnnotations.StringLength(500)]
        public string Description { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string IngredientsText { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string StepsText { get; set; } = string.Empty;
    }
}

